import org.owasp.encoder.Encode;

import java.io.FileWriter;
import java.io.IOException;

public class XSSSecureCode {

    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS attack!')</script>";

        // Properly sanitize user input to prevent XSS attacks
        String sanitizedInput = Encode.forHtml(userInput);

        // Output the sanitized result to a file
        try {
            FileWriter writer = new FileWriter("output.html");
            writer.write("<div>" + sanitizedInput + "</div>");
            writer.close();
            System.out.println("Sanitized output written to output.html");
        } catch (IOException e) {
            System.out.println("Error writing output to file: " + e.getMessage());
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
